use std::env;
use std::fs;
use std::io::{self, Write};
use std::path::{Path, PathBuf};
use std::collections::HashSet;

const MINIGIT_DIR: &str = ".minigit";
const INDEX_FILE: &str = ".minigit/index";
const COMMITS_DIR: &str = ".minigit/commits";
const LOG_FILE: &str = ".minigit/log";

fn ensure_minigit_dir() -> io::Result<()> {
    if !Path::new(MINIGIT_DIR).exists() {
        fs::create_dir(MINIGIT_DIR)?;
    }
    if !Path::new(COMMITS_DIR).exists() {
        fs::create_dir(COMMITS_DIR)?;
    }
    Ok(())
}

fn cmd_init() -> io::Result<()> {
    if Path::new(MINIGIT_DIR).exists() {
        println!("Repository already initialized.");
        return Ok(());
    }
    fs::create_dir(MINIGIT_DIR)?;
    fs::create_dir(COMMITS_DIR)?;
    fs::File::create(INDEX_FILE)?;
    fs::File::create(LOG_FILE)?;
    println!("Initialized empty minigit repository in {}", MINIGIT_DIR);
    Ok(())
}

fn cmd_add(filename: &str) -> io::Result<()> {
    if !Path::new(MINIGIT_DIR).exists() {
        println!("Not a minigit repository (or any parent directory)");
        return Ok(());
    }
    let mut index = if Path::new(INDEX_FILE).exists() {
        fs::read_to_string(INDEX_FILE)?
    } else {
        String::new()
    };
    let mut files: HashSet<&str> = index.lines().collect();
    if files.contains(filename) {
        return Ok(()); // Already staged
    }
    if !Path::new(filename).exists() {
        println!("fatal: pathspec '{}' did not match any files", filename);
        return Ok(());
    }
    index.push_str(filename);
    index.push('\n');
    fs::write(INDEX_FILE, index)?;
    Ok(())
}

fn cmd_status() -> io::Result<()> {
    if !Path::new(MINIGIT_DIR).exists() {
        println!("Not a minigit repository.");
        return Ok(());
    }
    let index = if Path::new(INDEX_FILE).exists() {
        fs::read_to_string(INDEX_FILE)?
    } else {
        "".to_string()
    };
    let staged: Vec<&str> = index.lines().collect();
    if staged.is_empty() {
        println!("No files staged.");
    } else {
        println!("Staged files:");
        for f in staged {
            println!("  {}", f);
        }
    }
    Ok(())
}

fn cmd_commit(msg: &str) -> io::Result<()> {
    if !Path::new(MINIGIT_DIR).exists() {
        println!("Not a minigit repository");
        return Ok(());
    }

    let index = fs::read_to_string(INDEX_FILE)?;
    let staged: Vec<&str> = index.lines().collect();

    if staged.is_empty() {
        println!("No changes added to commit");
        return Ok(());
    }

    let commit_id = get_next_commit_id()?;
    let commit_dir = format!("{}/{}", COMMITS_DIR, commit_id);
    fs::create_dir(&commit_dir)?;

    for filename in &staged {
        if Path::new(filename).exists() {
            fs::copy(filename, format!("{}/{}", commit_dir, filename))?;
        }
    }

    // log: id message nl
    let mut log = fs::OpenOptions::new()
        .append(true)
        .create(true)
        .open(LOG_FILE)?;
    writeln!(log, "{} {}", commit_id, msg)?;

    // Clear index
    fs::write(INDEX_FILE, "")?;

    println!("Committed as {}", commit_id);
    Ok(())
}

fn get_next_commit_id() -> io::Result<u32> {
    let paths = fs::read_dir(COMMITS_DIR)?;
    let mut max_id = 0;
    for entry in paths {
        if let Ok(entry) = entry {
            if let Some(fname) = entry.file_name().to_str() {
                if let Ok(id) = fname.parse::<u32>() {
                    if id > max_id {
                        max_id = id;
                    }
                }
            }
        }
    }
    Ok(max_id + 1)
}

fn cmd_log() -> io::Result<()> {
    if !Path::new(MINIGIT_DIR).exists() {
        println!("Not a minigit repository.");
        return Ok(());
    }
    let log = fs::read_to_string(LOG_FILE)?;
    if log.trim().is_empty() {
        println!("No commits yet.");
        return Ok(());
    }
    for line in log.lines().rev() {
        let mut split = line.splitn(2, ' ');
        if let (Some(id), Some(msg)) = (split.next(), split.next()) {
            println!("commit {}\n    {}", id, msg);
        }
    }
    Ok(())
}

fn main() -> io::Result<()> {
    let args: Vec<String> = env::args().collect();
    if args.len() < 2 {
        println!("minigit: missing subcommand. Try 'init', 'add', 'commit', 'status', 'log'");
        return Ok(());
    }
    match args[1].as_str() {
        "init" => cmd_init(),
        "add" => {
            if args.len() < 3 {
                println!("minigit add <filename>");
                return Ok(());
            }
            cmd_add(&args[2])
        }
        "status" => cmd_status(),
        "commit" => {
            if args.len() < 3 {
                println!("minigit commit <message>");
                return Ok(());
            }
            cmd_commit(&args[2..].join(" "))
        }
        "log" => cmd_log(),
        _ => {
            println!("minigit: unknown command '{}'", args[1]);
            Ok(())
        }
    }
}
```

